class Solution {
    public int nthUglyNumber(int n) {
        int[] ugly = new int[n];
        ugly[0] = 1;
        int i = 0, j = 0, k = 0;
        for (int index = 1; index < n; index++) {
            int next2 = ugly[i] * 2;
            int next3 = ugly[j] * 3;
            int next5 = ugly[k] * 5;
            int next = Math.min(Math.min(next2, next3), next5);
            ugly[index] = next;
            if (next == next2) i++;
            if (next == next3) j++;
            if (next == next5) k++;
        }
        return ugly[n - 1];
    }
}

